module div_8bit(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);

parameter IDLE = 3'b000, START = 3'b001, SUB = 3'b010, MUX_SEL = 3'b011, SHIFT_L = 3'b100, DONE = 3'b101;
reg [2:0] state, next_state;
reg [7:0] neg_divisor;
reg [15:0] sr;
reg [3:0] cnt;
reg start_cnt;

wire [7:0] dividend_abs;
wire [8:0] dividend_abs_extend;
wire [8:0] sr_sub_neg_divisor;
wire [8:0] mux_result;
wire co;

assign dividend_abs = (sign && dividend[7]) ? (~dividend + 1) : dividend;
assign dividend_abs_extend = {1'b0, dividend_abs};
assign sr_sub_neg_divisor = sr[8:0] - {1'b0, neg_divisor};
assign mux_result = co ? sr_sub_neg_divisor[8:1] : sr[8:1];
assign co = sr_sub_neg_divisor[8];

always @(posedge clk or negedge rst) begin
    if (!rst) begin
        state <= IDLE;
        neg_divisor <= 8'b0;
        sr <= 16'b0;
        cnt <= 4'b0;
        start_cnt <= 1'b0;
        res_valid <= 1'b0;
    end else begin
        state <= next_state;
        if (state == START) begin
            neg_divisor <= (sign && divisor[7]) ? (~divisor + 1) : divisor;
            sr <= {dividend_abs_extend, 1'b0};
        end else if (state == SHIFT_L) begin
            sr <= {mux_result, sr[0], 1'b0};
        end
    end
end

always @(*) begin
    case (state)
        IDLE: begin
            if (opn_valid && !res_valid) begin
                next_state = START;
            end else begin
                next_state = IDLE;
            end
        end
        START: begin
            if (cnt == 4'b1000) begin
                next_state = DONE;
            end else begin
                next_state = SUB;
            end
        end
        SUB: begin
            next_state = MUX_SEL;
        end
        MUX_SEL: begin
            next_state = SHIFT_L;
        end
        SHIFT_L: begin
            if (cnt == 4'b1000) begin
                next_state = DONE;
            end else begin
                next_state = SUB;
            end
        end
        DONE: begin
            next_state = IDLE;
        end
        default: begin
            next_state = IDLE;
        end
    endcase
end

always @(posedge clk or negedge rst) begin
    if (!rst) begin
        cnt <= 4'b0;
        start_cnt <= 1'b0;
    end else if (state == START) begin
        cnt <= 4'b0000;
        start_cnt <= 1'b1;
    end else if (state == SUB) begin
        cnt <= cnt + 1;
    end else if (state == SHIFT_L) begin
        start_cnt <= 1'b0;
    end
end

always @(posedge clk or negedge rst) begin
    if (!rst) begin
        res_valid <= 1'b0;
    end else if (state == DONE) begin
        res_valid <= 1'b1;
    end else if (res_valid && res_ready) begin
        res_valid <= 1'b0;
    end
end

always @(posedge clk) begin
    if (state == DONE) begin
        result <= {sr[15:8], sr[7:0]};
    end
end

endmodule
